   132	static void e1ap_setup_failure(sctp_assoc_t assoc_id, uint64_t transac_id)
   133	{
   134	  MessageDef *msg_p = itti_alloc_new_message(TASK_RRC_GNB, 0, E1AP_SETUP_FAIL);
   135	  msg_p->ittiMsgHeader.originInstance = assoc_id;
   136	  e1ap_setup_fail_t *setup_fail = &E1AP_SETUP_FAIL(msg_p);
   137	  setup_fail->transac_id = transac_id;
   138	  LOG_I(NR_RRC, "Triggering E1AP Setup Failure for transac_id %ld, assoc_id %ld\n",
   139	        transac_id,
   140	        msg_p->ittiMsgHeader.originInstance);
   141	  itti_send_msg_to_task(TASK_CUCP_E1, 0 /*unused by callee*/, msg_p);
   142	}
