   144	/**
   145	 * @brief E1AP Setup Request processing on CU-CP
   146	*/
   147	int rrc_gNB_process_e1_setup_req(sctp_assoc_t assoc_id, e1ap_setup_req_t *req)
   148	{
   149	  AssertFatal(req->supported_plmns <= PLMN_LIST_MAX_SIZE, "Supported PLMNs is more than PLMN_LIST_MAX_SIZE\n");
   150	  gNB_RRC_INST *rrc = RC.nrrrc[0];
   151	
   152	  nr_rrc_cuup_container_t *c = NULL;
   153	  RB_FOREACH(c, rrc_cuup_tree, &rrc->cuups) {
   154	    if (req->gNB_cu_up_id == c->setup_req->gNB_cu_up_id) {
   155	      LOG_E(NR_RRC,
   156	            "Connecting CU-UP ID %ld name %s (assoc_id %d) has same ID as existing CU-UP ID %ld name %s (assoc_id %d)\n",
   157	            req->gNB_cu_up_id,
   158	            req->gNB_cu_up_name,
   159	            assoc_id,
   160	            c->setup_req->gNB_cu_up_id,
   161	            c->setup_req->gNB_cu_up_name,
   162	            c->assoc_id);
   163	      e1ap_setup_failure(assoc_id, req->transac_id);
   164	      return -1;
   165	    }
   166	  }
   167	
   168	  for (int i = 0; i < req->supported_plmns; i++) {
   169	    PLMN_ID_t *id = &req->plmn[i].id;
   170	    if (rrc->configuration.mcc[i] != id->mcc || rrc->configuration.mnc[i] != id->mnc) {
   171	      LOG_E(NR_RRC,
   172	            "PLMNs received from CUUP (mcc:%d, mnc:%d) did not match with PLMNs in RRC (mcc:%d, mnc:%d)\n",
   173	            id->mcc,
   174	            id->mnc,
   175	            rrc->configuration.mcc[i],
   176	            rrc->configuration.mnc[i]);
   177	      e1ap_setup_failure(assoc_id, req->transac_id);
   178	      return -1;
   179	    }
   180	  }
   181	
   182	  LOG_I(NR_RRC, "Accepting new CU-UP ID %ld name %s (assoc_id %d)\n", req->gNB_cu_up_id, req->gNB_cu_up_name, assoc_id);
   183	  nr_rrc_cuup_container_t *cuup = malloc(sizeof(*cuup));
   184	  AssertFatal(cuup, "out of memory\n");
   185	  cuup->setup_req = malloc(sizeof(*cuup->setup_req));
   186	  *cuup->setup_req = *req;
   187	  cuup->assoc_id = assoc_id;
   188	  RB_INSERT(rrc_cuup_tree, &rrc->cuups, cuup);
   189	  rrc->num_cuups++;
   190	
   191	  MessageDef *msg_p = itti_alloc_new_message(TASK_RRC_GNB, 0, E1AP_SETUP_RESP);
   192	  msg_p->ittiMsgHeader.originInstance = assoc_id;
   193	  e1ap_setup_resp_t *resp = &E1AP_SETUP_RESP(msg_p);
   194	  resp->transac_id = req->transac_id;
   195	  itti_send_msg_to_task(TASK_CUCP_E1, 0, msg_p);
   196	
   197	  return 0;
   198	}
